import type { ReactNode } from "react"
import { DocsSidebar } from "@/components/docs/DocsSidebar"

interface DocsShellProps {
  title: string
  description?: string
  children: ReactNode
}

/**
 * A shell component for the documentation pages.
 *
 * It renders a sidebar with all the available documentation pages,
 * and a main content area where the actual documentation page is rendered.
 *
 * It also renders a title and an optional description at the top of the page.
 *
 * @param {string} title - The title of the documentation page.
 * @param {string} [description] - An optional description for the documentation page.
 * @param {ReactNode} children - The actual documentation page content.
 *
 * @returns {ReactNode} A React component representing the documentation page shell.
 */
export function DocsShell({ title, description, children }: DocsShellProps): ReactNode {
  return (
    <div className="mx-auto flex max-w-7xl">
      <DocsSidebar />
      <div className="min-h-screen flex-1 px-6 py-10">
        <header className="mb-10">
          <p className="text-sm uppercase tracking-[0.2em] text-muted-foreground">
            Documentation
          </p>
          <h1 className="mt-3 text-4xl font-bold tracking-tight">{title}</h1>
          {description ? (
            <p className="mt-4 max-w-2xl text-base text-muted-foreground">
              {description}
            </p>
          ) : null}
        </header>

        <main className="prose prose-neutral dark:prose-invert max-w-none">
          {children}
        </main>
      </div>
    </div>
  )
}
