import { notFound } from "next/navigation"
import { DocsShell } from "@/components/docs/DocsShell"
import { getAllDocs, getDocBySlug } from "@/lib/docs/docs.source"
import { renderDoc } from "@/lib/docs/docs.mdx"

interface DocPageProps {
  params: Promise<{
    slug?: string[]
  }>
}

export async function generateStaticParams() {
  return getAllDocs().map((doc) => ({
    slug: doc.slug,
  }))
}

export async function generateMetadata({ params }: DocPageProps) {
  const { slug = [] } = await params
  const doc = getDocBySlug(slug)

  if (!doc) {
    return {}
  }

  return {
    title: doc.title,
    description: doc.description,
  }
}

export default async function DocPage({ params }: DocPageProps) {
  const { slug = [] } = await params
  const doc = getDocBySlug(slug)

  if (!doc) {
    notFound()
  }

  const rendered = await renderDoc(slug)

  return (
    <DocsShell title={rendered.frontmatter.title} description={rendered.frontmatter.description}>
      {rendered.content}
    </DocsShell>
  )
}
