import fs from "node:fs"
import matter from "gray-matter"
import path from "node:path"
import type { JSX } from "react"

import { getDocFilePath } from "@/lib/docs/docs.source"
import type { DocFrontmatter } from "@/lib/docs/docs.types"

export async function renderDoc(slug: string[]): Promise<{
  Content: React.ComponentType
  frontmatter: DocFrontmatter
}> {
  const filePath = getDocFilePath(slug)

  const source = fs.readFileSync(filePath, "utf8")

  const { data } = matter(source)

  const modulePath = path
    .relative(process.cwd(), filePath)
    .replace(/\.mdx$/, "")

  const Content = (await import(`@/${modulePath}.mdx`)).default

  return {
    Content,
    frontmatter: {
      title:
        typeof data.title === "string"
          ? data.title
          : slug.at(-1) ?? "Untitled",

      description:
        typeof data.description === "string"
          ? data.description
          : undefined,

      section:
        typeof data.section === "string"
          ? data.section
          : undefined,

      order:
        typeof data.order === "number"
          ? data.order
          : undefined,
    },
  }
}