import fs from "node:fs"
import path from "node:path"
import matter from "gray-matter"
import type { DocEntry, DocFrontmatter } from "@/lib/docs/docs.types"

const DOCS_ROOT = path.join(process.cwd(), "content", "docs")

function isMdxFile(filename: string): boolean {
  return filename.endsWith(".mdx")
}

function slugFromFilePath(filePath: string): string[] {
  const relative = path.relative(DOCS_ROOT, filePath)
  return relative.replace(/\.mdx$/, "").split(path.sep)
}

function hrefFromSlug(slug: string[]): string {
  return `/docs/${slug.join("/")}`
}

function readFrontmatter(filePath: string): DocFrontmatter {
  const source = fs.readFileSync(filePath, "utf8")
  const { data } = matter(source)

  return {
    title: typeof data.title === "string" ? data.title : slugFromFilePath(filePath).at(-1) ?? "Untitled",
    description: typeof data.description === "string" ? data.description : undefined,
    section: typeof data.section === "string" ? data.section : undefined,
    order: typeof data.order === "number" ? data.order : undefined,
  }
}

function walkDocs(dirPath: string, acc: string[] = []): string[] {
  for (const entry of fs.readdirSync(dirPath, { withFileTypes: true })) {
    const fullPath = path.join(dirPath, entry.name)

    if (entry.isDirectory()) {
      walkDocs(fullPath, acc)
      continue
    }

    if (entry.isFile() && isMdxFile(entry.name)) {
      acc.push(fullPath)
    }
  }

  return acc
}

export function getAllDocs(): DocEntry[] {
  const files = walkDocs(DOCS_ROOT)

  return files
    .map((filePath) => {
      const slug = slugFromFilePath(filePath)
      const frontmatter = readFrontmatter(filePath)

      return {
        ...frontmatter,
        slug,
        href: hrefFromSlug(slug),
      }
    })
    .sort((a, b) => {
      const sectionA = a.section ?? ""
      const sectionB = b.section ?? ""

      if (sectionA !== sectionB) {
        return sectionA.localeCompare(sectionB)
      }

      const orderA = a.order ?? Number.MAX_SAFE_INTEGER
      const orderB = b.order ?? Number.MAX_SAFE_INTEGER

      if (orderA !== orderB) {
        return orderA - orderB
      }

      return a.title.localeCompare(b.title)
    })
}

export function getDocBySlug(slug: string[]): DocEntry | null {
  return getAllDocs().find((doc) => doc.slug.join("/") === slug.join("/")) ?? null
}

export function getDocFilePath(slug: string[]): string {
  return path.join(DOCS_ROOT, ...slug) + ".mdx"
}

export function getDocSections() {
  const docs = getAllDocs()
  const sections = new Map<string, DocEntry[]>()

  for (const doc of docs) {
    const section = doc.section ?? "Documentation"
    const items = sections.get(section) ?? []
    items.push(doc)
    sections.set(section, items)
  }

  return Array.from(sections.entries()).map(([title, items]) => ({
    title,
    items,
  }))
}
